steps.input:
node - <<'NODE'
const meshes = { A: {elements:13000, stress:185, disp:1.44}, B: {elements:50000, stress:199, disp:1.53}, C: {elements:113000, stress:202, disp:1.55} };
function pct(a,b){return Math.abs(b-a)/a*100;}
for (const [from,to] of [['A','B'],['B','C'],['A','C']]) {
  const x=meshes[from], y=meshes[to];
  console.log(`${from}->${to} stress rel to ${from}:`, pct(x.stress,y.stress));
  console.log(`${from}->${to} disp rel to ${from}:`, pct(x.disp,y.disp));
  console.log(`${from}->${to} stress rel to ${to}:`, Math.abs(y.stress-x.stress)/y.stress*100);
  console.log(`${from}->${to} disp rel to ${to}:`, Math.abs(y.disp-x.disp)/y.disp*100);
}
NODE

